var surah057 = {
  number: 57,
  nameArabic: "al-Hadid",
  nameEnglish: "Al-Hadid",
  meaning: "The Iron",
  totalAyahs: 29,
  ayahs: [
    { number: 1, arabic: "سَبَّحَ لِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "Sabbaha lillahi ma fee alssamawati waalardi wahuwa alAAazeezu alhakeemu", transliterationB: "Sabbaha lillaahi maa fissamaawaati wal ardi wa Huwal 'Azeezul Hakeem", english: "Whatever is in the heavens and on earth,- let it declare the Praises and Glory of Allah: for He is the Exalted in Might, the Wise", romanUrdu: "Allah ki tasbeeh ki hai har us cheez ne jo zameen aur aasmano mein hai, Aur wahi zabardast daana (wise) hai" },
    { number: 2, arabic: "لَهُۥ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ يُحْىِۦ وَيُمِيتُ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ", transliteration: "Lahu mulku alssamawati waalardi yuhyee wayumeetu wahuwa AAala kulli shayin qadeerun", transliterationB: "Lahoo mulkus samaawaati wal ardi yuhyee wa yumeetu wa Huwa 'alaa kulli shai'in Qadeer", english: "To Him belongs the dominion of the heavens and the earth: It is He Who gives Life and Death; and He has Power over all things", romanUrdu: "Zameen aur aasmano ki sultanat ka maalik wahi hai, zindagi bakshta hai aur maut deta hai, aur har cheez par qudrat rakhta hai" },
    { number: 3, arabic: "هُوَ ٱلْأَوَّلُ وَٱلْءَاخِرُ وَٱلظَّٰهِرُ وَٱلْبَاطِنُ ۖ وَهُوَ بِكُلِّ شَىْءٍ عَلِيمٌ", transliteration: "Huwa alawwalu waalakhiru waalththahiru waalbatinu wahuwa bikulli shayin AAaleemun", transliterationB: "Huwal Awwalu wal'Aakhiru waz Zaahiru wal Baatinu wa huwa bikulli shai'in Aleem", english: "He is the First and the Last, the Evident and the Immanent: and He has full knowledge of all things", romanUrdu: "Wahi awwal bhi hai aur aakhir bhi, aur zaahir bhi hai aur makhfi(hiddin) bhi , aur woh har cheez ka ilm rakhta hai" },
    { number: 4, arabic: "هُوَ ٱلَّذِى خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ فِى سِتَّةِ أَيَّامٍۢ ثُمَّ ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ ۚ يَعْلَمُ مَا يَلِجُ فِى ٱلْأَرْضِ وَمَا يَخْرُجُ مِنْهَا وَمَا يَنزِلُ مِنَ ٱلسَّمَآءِ وَمَا يَعْرُجُ فِيهَا ۖ وَهُوَ مَعَكُمْ أَيْنَ مَا كُنتُمْ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌۭ", transliteration: "Huwa allathee khalaqa alssamawati waalarda fee sittati ayyamin thumma istawa AAala alAAarshi yaAAlamu ma yaliju fee alardi wama yakhruju minha wama yanzilu mina alssamai wama yaAAruju feeha wahuwa maAAakum ayna ma kuntum waAllahu bima taAAmaloona baseerun", transliterationB: "Huwal lazee khalaqas samaawaati wal arda fee sittati ayyaamin summas tawaa 'alal 'Arsh; ya'lamu maa yaliju filardi wa maa yakhruju minhaa wa maa yanzilu minas samaaa'i wa maa ya'ruju feeha wa Huwa ma'akum ayna maa kuntum; wallaahu bimaa ta'maloona Baseer", english: "He it is Who created the heavens and the earth in Six Days, and is moreover firmly established on the Throne (of Authority). He knows what enters within the earth and what comes forth out of it, what comes down from heaven and what mounts up to it. And He is with you wheresoever ye may be. And Allah sees well all that ye do", romanUrdu: "Wahi hai jisne aasmano aur zameen ko chey (six) dino mein paida kiya aur phir arsh par jalwa farma hua. Uske ilm mein hai jo kuch zameen mein jata hai aur jo kuch ussey nikalta hai, aur jo kuch aasman se utarta hai aur jo kuch usmein chadhta hai. Woh tumhare saath hai jahan bhi tum ho. Jo kaam bhi karte ho usey woh dekh raha hai" },
    { number: 5, arabic: "لَّهُۥ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ", transliteration: "Lahu mulku alssamawati waalardi waila Allahi turjaAAu alomooru", transliterationB: "Lahoo mulkus samaawaati wal ard; wa ilal laahi turja'ul umoor", english: "To Him belongs the dominion of the heavens and the earth: and all affairs are referred back to Allah", romanUrdu: "Wahi zameen aur aasmano ki baadshahi ka maalik hai aur tamaam maamlaat faisley ke liye usi ki taraf ruju kiye jatey hain" },
    { number: 6, arabic: "يُولِجُ ٱلَّيْلَ فِى ٱلنَّهَارِ وَيُولِجُ ٱلنَّهَارَ فِى ٱلَّيْلِ ۚ وَهُوَ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ", transliteration: "Yooliju allayla fee alnnahari wayooliju alnnahara fee allayi wahuwa AAaleemun bithati alssudoori", transliterationB: "Yoolijul laila fin nahaari wa yoolijun nahaara fil lail; wa Huwa 'Aleemum bizaatis sudoor", english: "He merges Night into Day, and He merges Day into Night; and He has full knowledge of the secrets of (all) hearts", romanUrdu: "Wahi raat ko din mein aur din ko raat mein daakhil karta hai, aur dilon ke chupey huye raaz tak janta hai" },
    { number: 7, arabic: "ءَامِنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَأَنفِقُوا۟ مِمَّا جَعَلَكُم مُّسْتَخْلَفِينَ فِيهِ ۖ فَٱلَّذِينَ ءَامَنُوا۟ مِنكُمْ وَأَنفَقُوا۟ لَهُمْ أَجْرٌۭ كَبِيرٌۭ", transliteration: "Aminoo biAllahi warasoolihi waanfiqoo mimma jaAAalakum mustakhlafeena feehi faallatheena amanoo minkum waanfaqoo lahum ajrun kabeerun", transliterationB: "Aaaminoo billaahi wa Rasoolihee wa anfiqoo mimmaa ja'alakum mustakh lafeena feehi fallazeena aamanoo minkum wa anfaqoo lahum ajrun kabeer", english: "Believe in Allah and His messenger, and spend (in charity) out of the (substance) whereof He has made you heirs. For, those of you who believe and spend (in charity),- for them is a great Reward", romanUrdu: "Iman lao Allah aur uske Rasool par aur kharch karo un cheezon mein se jinpar usney tumko khalifa banaya hai. Jo log tum mein se iman layenge aur maal kharch karenge unke liye bada ajr hai" },
    { number: 8, arabic: "وَمَا لَكُمْ لَا تُؤْمِنُونَ بِٱللَّهِ ۙ وَٱلرَّسُولُ يَدْعُوكُمْ لِتُؤْمِنُوا۟ بِرَبِّكُمْ وَقَدْ أَخَذَ مِيثَٰقَكُمْ إِن كُنتُم مُّؤْمِنِينَ", transliteration: "Wama lakum la tuminoona biAllahi waalrrasoolu yadAAookum lituminoo birabbikum waqad akhatha meethaqakum in kuntum mumineena", transliterationB: "Wa maa lakum laa tu'minoona billaahi war Rasoolu yad'ookum lituu'minoo bi Rabbikum wa qad akhaza meesaaqakum in kuntum mu'mineen", english: "What cause have ye why ye should not believe in Allah?- and the Messenger invites you to believe in your Lord, and has indeed taken your Covenant, if ye are men of Faith", romanUrdu: "Tumhein kya ho gaya hai ke tum Allah par iman nahin latey halanke Rasool tumhein apne Rubb par iman laney ki dawat de raha hai, aur woh tumse ahad (covenant) le chuka hai, agar tum waqayi maanne waley ho" },
    { number: 9, arabic: "هُوَ ٱلَّذِى يُنَزِّلُ عَلَىٰ عَبْدِهِۦٓ ءَايَٰتٍۭ بَيِّنَٰتٍۢ لِّيُخْرِجَكُم مِّنَ ٱلظُّلُمَٰتِ إِلَى ٱلنُّورِ ۚ وَإِنَّ ٱللَّهَ بِكُمْ لَرَءُوفٌۭ رَّحِيمٌۭ", transliteration: "Huwa allathee yunazzilu AAala AAabdihi ayatin bayyinatin liyukhrijakum mina alththulumati ila alnnoori wainna Allaha bikum laraoofun raheemun", transliterationB: "Huwal lazee yunazzilu 'alaa 'abdiheee Aayaatim baiyinaatil liyukhrijakum minaz zulumaati ilan noor; wa innal laaha bikum la Ra'oofur Raheem", english: "He is the One Who sends to His Servant Manifest Signs, that He may lead you from the depths of Darkness into the Light and verily Allah is to you most kind and Merciful", romanUrdu: "Woh Allah hi to hai jo apne banday par saaf saaf aayatein nazil kar raha hai taa-ke tumhein tareekhiyon (darkness) se nikal kar roshni mein le aaye. Aur haqeeat yeh hai ke Allah tumpar nihayat shafeeq aur meharbaan hai" },
    { number: 10, arabic: "وَمَا لَكُمْ أَلَّا تُنفِقُوا۟ فِى سَبِيلِ ٱللَّهِ وَلِلَّهِ مِيرَٰثُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ لَا يَسْتَوِى مِنكُم مَّنْ أَنفَقَ مِن قَبْلِ ٱلْفَتْحِ وَقَٰتَلَ ۚ أُو۟لَٰٓئِكَ أَعْظَمُ دَرَجَةًۭ مِّنَ ٱلَّذِينَ أَنفَقُوا۟ مِنۢ بَعْدُ وَقَٰتَلُوا۟ ۚ وَكُلًّۭا وَعَدَ ٱللَّهُ ٱلْحُسْنَىٰ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌۭ", transliteration: "Wama lakum alla tunfiqoo fee sabeeli Allahi walillahi meerathu alssamawati waalardi la yastawee minkum man anfaqa min qabli alfathi waqatala olaika aAAthamu darajatan mina allatheena anfaqoo min baAAdu waqataloo wakullan waAAada Allahu alhusna waAllahu bima taAAmaloona khabeerun", transliterationB: "Wa maa lakum allaa tunfiqoo fee sabeelil laahi wa lillaahi meeraasus samaawaati wal-ard; laa yastawee minkum man anfaqa min qablil fat-hi wa qaatal; ulaaaika a'zamu darajatam minal lazeena anfaqoo mim ba'du wa qaataloo; wa kullanw wa'adallaahul husnaa; wallaahu bimaa ta'maloona Khabeer", english: "And what cause have ye why ye should not spend in the cause of Allah?- For to Allah belongs the heritage of the heavens and the earth. Not equal among you are those who spent (freely) and fought, before the Victory, (with those who did so later). Those are higher in rank than those who spent (freely) and fought afterwards. But to all has Allah promised a goodly (reward). And Allah is well acquainted with all that ye do", romanUrdu: "Aakhir kya wajah hai ke tum Allah ki raah mein kharch nahin karte halanke zameen aur aasmano ki miraas (inheritance) Allah hi ke liye hai. Tum mein se jo log fatah ke baad kharch aur jihad karenge woh kabhi un logon ke barabar nahin ho sakte jinhon ne fatah se pehle kharch aur jihad kiya hai.Unka darja baad mein kharch aur jihad karne walon se badh-kar hai hai agarche Allah ne dono hi se acchey waade famaye hain. Jo kuch tum karte ho Allah ussey ba-khabar hai" },
    { number: 11, arabic: "مَّن ذَا ٱلَّذِى يُقْرِضُ ٱللَّهَ قَرْضًا حَسَنًۭا فَيُضَٰعِفَهُۥ لَهُۥ وَلَهُۥٓ أَجْرٌۭ كَرِيمٌۭ", transliteration: "Man tha allathee yuqridu Allaha qardan hasanan fayudaAAifahu lahu walahu ajrun kareemun", transliterationB: "man zal lazee yuqridul laaha qardan hasanan fa yudaa'ifahoo lahoo wa lahooo ajrun kareem", english: "Who is he that will Loan to Allah a beautiful loan? for (Allah) will increase it manifold to his credit, and he will have (besides) a liberal Reward", romanUrdu: "Kaun hai jo Allah ko qarz dey? Accha qarz taa-ke Allah usey kai gunaa bada kar wapas dey. Aur uske liye behtareen ajar hai" },
    { number: 12, arabic: "يَوْمَ تَرَى ٱلْمُؤْمِنِينَ وَٱلْمُؤْمِنَٰتِ يَسْعَىٰ نُورُهُم بَيْنَ أَيْدِيهِمْ وَبِأَيْمَٰنِهِم بُشْرَىٰكُمُ ٱلْيَوْمَ جَنَّٰتٌۭ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَا ۚ ذَٰلِكَ هُوَ ٱلْفَوْزُ ٱلْعَظِيمُ", transliteration: "Yawma tara almumineena waalmuminati yasAAa nooruhum bayna aydeehim wabiaymanihim bushrakumu alyawma jannatun tajree min tahtiha alanharu khalideena feeha thalika huwa alfawzu alAAatheemu", transliterationB: "Yawma taral mu'mineena walmu'minaati yas'aa nooruhum baina aydeehim wa biaymaanihim bushraakumul yawma jannaatun tajree min tahtihal anhaaru khaalideena feeha; zaalika huwal fawzul 'azeem", english: "One Day shalt thou see the believing men and the believing women- how their Light runs forward before them and by their right hands: (their greeting will be): \"Good News for you this Day! Gardens beneath which flow rivers! to dwell therein for aye! This is indeed the highest Achievement", romanUrdu: "Us din jabke tum momin mardon aur auraton ko dekhoge ke unka noor unke aagey aagey aur unke dayein jaanib daud raha hoga (unse kaha jayega ke) aaj basharat (khushkhabri) hai. Tumhare liye jannatein hongi jinke nichey nehrein beh rahi hongi, jin mein woh hamesha rahenge. Yahi hai badi kamiyabi" },
    { number: 13, arabic: "يَوْمَ يَقُولُ ٱلْمُنَٰفِقُونَ وَٱلْمُنَٰفِقَٰتُ لِلَّذِينَ ءَامَنُوا۟ ٱنظُرُونَا نَقْتَبِسْ مِن نُّورِكُمْ قِيلَ ٱرْجِعُوا۟ وَرَآءَكُمْ فَٱلْتَمِسُوا۟ نُورًۭا فَضُرِبَ بَيْنَهُم بِسُورٍۢ لَّهُۥ بَابٌۢ بَاطِنُهُۥ فِيهِ ٱلرَّحْمَةُ وَظَٰهِرُهُۥ مِن قِبَلِهِ ٱلْعَذَابُ", transliteration: "Yawma yaqoolu almunafiqoona waalmunafiqatu lillatheena amanoo onthuroona naqtabis min noorikum qeela irjiAAoo waraakum failtamisoo nooran faduriba baynahum bisoorin lahu babun batinuhu feehi alrrahmatu wathahiruhu min qibalihi alAAathabu", transliterationB: "Yawma yaqoolul munaa fiqoona walmunaafiqaatu lillazeena aamanun zuroonaa naqtabis min noorikum qeelarji'oo waraaa'akum faltamisoo nooran faduriba bainahum bisooril lahoo baab, baatinuhoo feehir rahmatu wa zaahiruhoo min qibalihi-'azaab", english: "One Day will the Hypocrites- men and women - say to the Believers: \"Wait for us! Let us borrow (a Light) from your Light!\" It will be said: \"Turn ye back to your rear! then seek a Light (where ye can)!\" So a wall will be put up betwixt them, with a gate therein. Within it will be Mercy throughout, and without it, all alongside, will be (Wrath and) Punishment", romanUrdu: "Us roz munafik mardon aur auraton ka haal yeh hoga ke woh momino se kahenge zara hamari taraf dekho taa-ke hum tumhare noor se kuch fayda uthayein. Magar unse kaha jayega pichey hatt jao, Apna noor kahin aur talash karo. Phir unke darmiyan ek deewar hayal kardi jayegi jismein ek darwaza hoga us darwaze ke andar rehmat hogi aur bahar azaab" },
    { number: 14, arabic: "يُنَادُونَهُمْ أَلَمْ نَكُن مَّعَكُمْ ۖ قَالُوا۟ بَلَىٰ وَلَٰكِنَّكُمْ فَتَنتُمْ أَنفُسَكُمْ وَتَرَبَّصْتُمْ وَٱرْتَبْتُمْ وَغَرَّتْكُمُ ٱلْأَمَانِىُّ حَتَّىٰ جَآءَ أَمْرُ ٱللَّهِ وَغَرَّكُم بِٱللَّهِ ٱلْغَرُورُ", transliteration: "Yunadoonahum alam nakun maAAakum qaloo bala walakinnakum fatantum anfusakum watarabbastum wairtabtum wagharratkumu alamaniyyu hatta jaa amru Allahi wagharrakum biAllahi algharooru", transliterationB: "Yunaadoonahum alam nakum ma'akum qaaloo balaa wa laakinnakum fatantum anfusakum wa tarabbastum wartabtum wa gharratkumul amaaniyyu hatta jaaa'a amrul laahi wa gharrakum billaahil gharoor", english: "(Those without) will call out, \"Were we not with you?\" (The others) will reply, \"True! but ye led yourselves into temptation; ye looked forward (to our ruin); ye doubted (Allah's Promise); and (your false) desires deceived you; until there issued the Command of Allah. And the Deceiver deceived you in respect of Allah", romanUrdu: "Woh momino se pukar pukar kar kahenge kya hum tumhare saath na thay? Momin jawab dengey haan, magar tumne apne aap ko khud fitne mein dala, mauqa parasti ki, shakk mein padey rahey, aur jhooti tawakkuat (expectations) tumhein fareb deti rahi Yahan tak ke Allah ka faisla aa gaya. Aur aakhri waqt tak woh bada dhoke baaz tumhein Allah ke maamle mein dhoka deta raha" },
    { number: 15, arabic: "فَٱلْيَوْمَ لَا يُؤْخَذُ مِنكُمْ فِدْيَةٌۭ وَلَا مِنَ ٱلَّذِينَ كَفَرُوا۟ ۚ مَأْوَىٰكُمُ ٱلنَّارُ ۖ هِىَ مَوْلَىٰكُمْ ۖ وَبِئْسَ ٱلْمَصِيرُ", transliteration: "Faalyawma la yukhathu minkum fidyatun wala mina allatheena kafaroo mawakumu alnnaru hiya mawlakum wabisa almaseeru", transliterationB: "Fal Yawma laa yu'khazu minkum fidyatunw wa laa minal lazeena kafaroo; maawaakumun Naaru hiya maw laakum wa bi'sal maseer", english: "This Day shall no ransom be accepted of you, nor of those who rejected Allah.\" Your abode is the Fire: that is the proper place to claim you: and an evil refuge it is", romanUrdu: "Lihaza aaj na tumse koi fidiya kabool kiya jayega aur na un logon se jinhon ne khula khula kufr kiya tha. Tumhara thikana jahannum hai. Wahi tumhari khabar-giri karne wali hai aur yeh badtareen anjaam hai" },
    { number: 16, arabic: "۞ أَلَمْ يَأْنِ لِلَّذِينَ ءَامَنُوٓا۟ أَن تَخْشَعَ قُلُوبُهُمْ لِذِكْرِ ٱللَّهِ وَمَا نَزَلَ مِنَ ٱلْحَقِّ وَلَا يَكُونُوا۟ كَٱلَّذِينَ أُوتُوا۟ ٱلْكِتَٰبَ مِن قَبْلُ فَطَالَ عَلَيْهِمُ ٱلْأَمَدُ فَقَسَتْ قُلُوبُهُمْ ۖ وَكَثِيرٌۭ مِّنْهُمْ فَٰسِقُونَ", transliteration: "Alam yani lillatheena amanoo an takhshaAAa quloobuhum lithikri Allahi wama nazala mina alhaqqi wala yakoonoo kaallatheena ootoo alkitaba min qablu fatala AAalayhimu alamadu faqasat quloobuhum wakatheerun minhum fasiqoona", transliterationB: "Alam yaani laillzeena aamanooo an takhsha'a quloo buhum lizikril laahi wa maa nazala minal haqqi wa laa yakoonoo kallazeena ootul Kitaaba min qablu fataala 'alaihimul amadu faqasat quloobuhum wa kaseerum minhum faasiqoon", english: "Has not the Time arrived for the Believers that their hearts in all humility should engage in the remembrance of Allah and of the Truth which has been revealed (to them), and that they should not become like those to whom was given Revelation aforetime, but long ages passed over them and their hearts grew hard? For many among them are rebellious transgressors", romanUrdu: "Kya iman laney walon ke liye abhi woh waqt nahin aaya ke unke dil Allah ke zikr se pighlein aur uske nazil karda haqq ke aagey jhukein aur woh un logon ki tarah na ho jayein jinhein pehle kitaab di gayi thi, phir ek lambi muddat unpar guzar gayi to unke dil sakht ho gaye aur aaj unmein se aksar fasiq banay huey hain" },
    { number: 17, arabic: "ٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ يُحْىِ ٱلْأَرْضَ بَعْدَ مَوْتِهَا ۚ قَدْ بَيَّنَّا لَكُمُ ٱلْءَايَٰتِ لَعَلَّكُمْ تَعْقِلُونَ", transliteration: "IAAlamoo anna Allaha yuhyee alarda baAAda mawtiha qad bayyanna lakumu alayati laAAallakum taAAqiloona", transliterationB: "I'lamooo annal laaha yuhyil arda ba'da mawtihaa; qad baiyannaa lakumul Aayaati la'allakum ta'qiloon", english: "Know ye (all) that Allah giveth life to the earth after its death! already have We shown the Signs plainly to you, that ye may learn wisdom", romanUrdu: "Khoob jaan lo ke Allah zameen ko uski maut ke baad zindagi bakshta hai, humne nishaniyan tumko saaf saaf dikha di hai, shayad ke tum aqal se kaam lo" },
    { number: 18, arabic: "إِنَّ ٱلْمُصَّدِّقِينَ وَٱلْمُصَّدِّقَٰتِ وَأَقْرَضُوا۟ ٱللَّهَ قَرْضًا حَسَنًۭا يُضَٰعَفُ لَهُمْ وَلَهُمْ أَجْرٌۭ كَرِيمٌۭ", transliteration: "Inna almussaddiqeena waalmussaddiqati waaqradoo Allaha qardan hasanan yudaAAafu lahum walahum ajrun kareemun", transliterationB: "Innal mussaddiqeena wal mussaddiqaati wa aqradul laaha qardan hassanany yudaa'afu lahum wa lahum ajrun kareem", english: "For those who give in Charity, men and women, and loan to Allah a Beautiful Loan, it shall be increased manifold (to their credit), and they shall have (besides) a liberal reward", romanUrdu: "Mardon aur auraton mein se jo log sadaqaat (charity) dene waley hain aur jinhon ne Allah ko karz-e-hasan diya hai, unko yakeenan kayi gunaa bada kar diya jayega aur unke liye behtareen ajar hai" },
    { number: 19, arabic: "وَٱلَّذِينَ ءَامَنُوا۟ بِٱللَّهِ وَرُسُلِهِۦٓ أُو۟لَٰٓئِكَ هُمُ ٱلصِّدِّيقُونَ ۖ وَٱلشُّهَدَآءُ عِندَ رَبِّهِمْ لَهُمْ أَجْرُهُمْ وَنُورُهُمْ ۖ وَٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَٰتِنَآ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلْجَحِيمِ", transliteration: "Waallatheena amanoo biAllahi warusulihi olaika humu alssiddeeqoona waalshshuhadao AAinda rabbihim lahum ajruhum wanooruhum waallatheena kafaroo wakaththaboo biayatina olaika ashabu aljaheemi", transliterationB: "Wallazeena aamanoo billaahi wa Rusuliheee ulaaa'ika humus siddeeqoona wash shuhadaaa'u 'inda Rabbihim lahum ajruhum wa nooruhum wallazeena kafaroo wa kazzaboo bi aayaatinaaa ulaaaika As haabul jaheem", english: "And those who believe in Allah and His messengers- they are the Sincere (lovers of Truth), and the witnesses (who testify), in the eyes of their Lord: They shall have their Reward and their Light. But those who reject Allah and deny Our Signs,- they are the Companions of Hell-Fire", romanUrdu: "Aur jo log Allah aur uske Rasoolon par iman laye hain wahi apne Rubb ke nazdeek siddiq aur shaheed hain. Unke liye unka ajar aur unka noor hai. Aur jin logon ne kufr kiya hai aur hamari aayat ko jhutlaya hai woh dozakhi hai" },
    { number: 20, arabic: "ٱعْلَمُوٓا۟ أَنَّمَا ٱلْحَيَوٰةُ ٱلدُّنْيَا لَعِبٌۭ وَلَهْوٌۭ وَزِينَةٌۭ وَتَفَاخُرٌۢ بَيْنَكُمْ وَتَكَاثُرٌۭ فِى ٱلْأَمْوَٰلِ وَٱلْأَوْلَٰدِ ۖ كَمَثَلِ غَيْثٍ أَعْجَبَ ٱلْكُفَّارَ نَبَاتُهُۥ ثُمَّ يَهِيجُ فَتَرَىٰهُ مُصْفَرًّۭا ثُمَّ يَكُونُ حُطَٰمًۭا ۖ وَفِى ٱلْءَاخِرَةِ عَذَابٌۭ شَدِيدٌۭ وَمَغْفِرَةٌۭ مِّنَ ٱللَّهِ وَرِضْوَٰنٌۭ ۚ وَمَا ٱلْحَيَوٰةُ ٱلدُّنْيَآ إِلَّا مَتَٰعُ ٱلْغُرُورِ", transliteration: "IAAlamoo annama alhayatu alddunya laAAibun walahwun wazeenatun watafakhurun baynakum watakathurun fee alamwali waalawladi kamathali ghaythin aAAjaba alkuffara nabatuhu thumma yaheeju fatarahu musfarran thumma yakoonu hutaman wafee alakhirati AAathabun shadeedun wamaghfiratun mina Allahi waridwanun wama alhayatu alddunya illa mataAAu alghuroori", transliterationB: "I'lamooo annamal hayaa tud dunyaa la'ibunw wa lahwunw wa zeenatunw wa takaasurun bainakum wa takaasurn fil amwaali wal awlaad, kamasali ghaisin a'jabal kuffaara nabaatuhoo summa yaheeju fataraahu musfaaran summa yakoonu hutaamaa; wa fil aakhirati 'azaabun shadeedunw wa magh firatum minal laahi wa ridwaan; wa mal haiyaa tuddun yaaa illaa mataa'ul ghuroor", english: "Know ye (all), that the life of this world is but play and amusement, pomp and mutual boasting and multiplying, (in rivalry) among yourselves, riches and children. Here is a similitude: How rain and the growth which it brings forth, delight (the hearts of) the tillers; soon it withers; thou wilt see it grow yellow; then it becomes dry and crumbles away. But in the Hereafter is a Penalty severe (for the devotees of wrong). And Forgiveness from Allah and (His) Good Pleasure (for the devotees of Allah). And what is the life of this world, but goods and chattels of deception", romanUrdu: "Khoob jaan lo ke yeh duniya ki zindagi iske siwa kuch nahin ke ek khel aur dil-lagi aur zaahiri tip top aur tumhara aapas mein ek dusre par fakr jatana aur maal-o-aulad mein ek dusre se badh janey ki koshish karna hai.Iski misal aisi hai jaise ek baarish ho gayi to usse paida honay wali nabataat(vegetation) ko dekh kar kaasht-kaar (kisan) khush ho gaye. Phir wahi kheti pak jati hai aur tum dekhte ho ke woh zard (yellow) ho gayi phir woh bhus (chura chura /crumble) bankar reh jati hai. Iske baraks aakhirat woh jagah hai jahan sakht azaab hai aur Allah ki magfirat aur uski khushnudi hai. Dunkya ki zindagi ek dhoke ke tatti (means of deception) ke siwa kuch nahin" },
    { number: 21, arabic: "سَابِقُوٓا۟ إِلَىٰ مَغْفِرَةٍۢ مِّن رَّبِّكُمْ وَجَنَّةٍ عَرْضُهَا كَعَرْضِ ٱلسَّمَآءِ وَٱلْأَرْضِ أُعِدَّتْ لِلَّذِينَ ءَامَنُوا۟ بِٱللَّهِ وَرُسُلِهِۦ ۚ ذَٰلِكَ فَضْلُ ٱللَّهِ يُؤْتِيهِ مَن يَشَآءُ ۚ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ", transliteration: "Sabiqoo ila maghfiratin min rabbikum wajannatin AAarduha kaAAardi alssamai waalardi oAAiddat lillatheena amanoo biAllahi warusulihi thalika fadlu Allahi yuteehi man yashao waAllahu thoo alfadli alAAatheemi", transliterationB: "Saabiqooo ilaa maghfiratim mir Rabbikum wa jannatin 'arduhaa ka-'ardis samaaa'i wal ardi u'iddat lillazeena aamanoo billaahi wa Rusulih; zaalika fadlul laahi yu'teehi many yashaaa'; wal laahu zul fadlil 'azeem", english: "Be ye foremost (in seeking) Forgiveness from your Lord, and a Garden (of Bliss), the width whereof is as the width of heaven and earth, prepared for those who believe in Allah and His messengers: that is the Grace of Allah, which He bestows on whom he pleases: and Allah is the Lord of Grace abounding", romanUrdu: "Daudo (race) aur ek dusrey se aage badhne ki koshish karo apne Rubb ki magfirat aur uski jannat ki taraf jiski wussat (width) aasman-o-zameen jaisi hai. Jo muhayya ki gayi hai un logon ke liye jo Allah aur uske Rasoolon par iman laye hon. Yeh Allah ka fazl hai, jisey chahta hai ata farmata hai, aur Allah badey fazl wala hai" },
    { number: 22, arabic: "مَآ أَصَابَ مِن مُّصِيبَةٍۢ فِى ٱلْأَرْضِ وَلَا فِىٓ أَنفُسِكُمْ إِلَّا فِى كِتَٰبٍۢ مِّن قَبْلِ أَن نَّبْرَأَهَآ ۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌۭ", transliteration: "Ma asaba min museebatin fee alardi wala fee anfusikum illa fee kitabin min qabli an nabraaha inna thalika AAala Allahi yaseerun", transliterationB: "Maaa asaaba mim musee batin fil ardi wa laa feee anfusikum illaa fee kitaabim min qabli an nabra ahaa; innaa zaalika 'alal laahi yaseer", english: "No misfortune can happen on earth or in your souls but is recorded in a decree before We bring it into existence: That is truly easy for Allah", romanUrdu: "Koi museebat aisi nahin hai jo zameen mein ya tumhare apne nafs par nazil hoti ho aur humne usko paida karne se pehle ek kitaab mein likh na rakkha ho. Aisa karna Allah ke liye bahut aasaan kaam hai" },
    { number: 23, arabic: "لِّكَيْلَا تَأْسَوْا۟ عَلَىٰ مَا فَاتَكُمْ وَلَا تَفْرَحُوا۟ بِمَآ ءَاتَىٰكُمْ ۗ وَٱللَّهُ لَا يُحِبُّ كُلَّ مُخْتَالٍۢ فَخُورٍ", transliteration: "Likayla tasaw AAala ma fatakum wala tafrahoo bima atakum waAllahu la yuhibbu kulla mukhtalin fakhoorin", transliterationB: "Likailaa taasaw 'alaa maa faatakum wa laa tafrahoo bimaaa aataakum; wallaahu laa yuhibbu kulla mukhtaalin fakhoor", english: "In order that ye may not despair over matters that pass you by, nor exult over favours bestowed upon you. For Allah loveth not any vainglorious boaster", romanUrdu: "(Yeh sab kuch isliye hai) taa-ke jo kuch bhi nuksaan tumhein ho us par tum dil-shikasta (grieve) na hon aur jo kuch Allah tumhein ata farmaye uspar phool na jao. Allah aisey logon ko pasand nahin karta jo apne aap ko badi cheez samajhte hain aur fakr jatate hain" },
    { number: 24, arabic: "ٱلَّذِينَ يَبْخَلُونَ وَيَأْمُرُونَ ٱلنَّاسَ بِٱلْبُخْلِ ۗ وَمَن يَتَوَلَّ فَإِنَّ ٱللَّهَ هُوَ ٱلْغَنِىُّ ٱلْحَمِيدُ", transliteration: "Allatheena yabkhaloona wayamuroona alnnasa bialbukhli waman yatawalla fainna Allaha huwa alghaniyyu alhameedu", transliterationB: "Allazeeena yabkhaloona wa yaamuroonan naasa bil bukhl; wa many yatawalla fa innal laaha Huwal Ghaniyyul Hameed", english: "Such persons as are covetous and commend covetousness to men. And if any turn back (from Allah's Way), verily Allah is Free of all Needs, Worthy of all Praise", romanUrdu: "Jo khud bukhl (niggard/kanjusi) karte hain aur dusron ko bukhl par uksate hain. Ab agar koi ru-gardani (mooh pherna) karta hai to Allah be-niyaz aur satoda siffat (immensely praiseworthy) hai" },
    { number: 25, arabic: "لَقَدْ أَرْسَلْنَا رُسُلَنَا بِٱلْبَيِّنَٰتِ وَأَنزَلْنَا مَعَهُمُ ٱلْكِتَٰبَ وَٱلْمِيزَانَ لِيَقُومَ ٱلنَّاسُ بِٱلْقِسْطِ ۖ وَأَنزَلْنَا ٱلْحَدِيدَ فِيهِ بَأْسٌۭ شَدِيدٌۭ وَمَنَٰفِعُ لِلنَّاسِ وَلِيَعْلَمَ ٱللَّهُ مَن يَنصُرُهُۥ وَرُسُلَهُۥ بِٱلْغَيْبِ ۚ إِنَّ ٱللَّهَ قَوِىٌّ عَزِيزٌۭ", transliteration: "Laqad arsalna rusulana bialbayyinati waanzalna maAAahumu alkitaba waalmeezana liyaqooma alnnasu bialqisti waanzalna alhadeeda feehi basun shadeedun wamanafiAAu lilnnasi waliyaAAlama Allahu man yansuruhu warusulahu bialghaybi inna Allaha qawiyyun AAazeezun", transliterationB: "Laqad arsalnaa Rusulanaa bilbaiyinaati wa anzalnaa ma'ahumul Kitaaba wal Meezaana liyaqooman naasu bilqist, wa anzalnal hadeeda feehi baasun shadeedunw wa manaafi'u linnaasi wa liya'lamal laahu many yansuruhoo wa Rusulahoo bilghaib; innal laaha Qawiyyn 'Azeez", english: "We sent aforetime our messengers with Clear Signs and sent down with them the Book and the Balance (of Right and Wrong), that men may stand forth in justice; and We sent down Iron, in which is (material for) mighty war, as well as many benefits for mankind, that Allah may test who it is that will help, Unseen, Him and His messengers: For Allah is Full of Strength, Exalted in Might (and able to enforce His Will)", romanUrdu: "Humne apne Rasoolon ko saaf saaf nishaniyon aur hidayaat ke saath bheja, aur unke saath kitaab aur mizaan (balance) nazil ki taakay log insaf par qayam hon. Aur loha (Iron) utara jis mein bada zoar hai aur logon ke liye munafa hai. Yeh isliye kiya gaya hai ke Allah ko maloom ho jaye ke kaun usko dekhe bagair uski aur uske rasoolon ki madad karta hai. Yaqeenan Allah badi quwwat wala aur zabardast hai" },
    { number: 26, arabic: "وَلَقَدْ أَرْسَلْنَا نُوحًۭا وَإِبْرَٰهِيمَ وَجَعَلْنَا فِى ذُرِّيَّتِهِمَا ٱلنُّبُوَّةَ وَٱلْكِتَٰبَ ۖ فَمِنْهُم مُّهْتَدٍۢ ۖ وَكَثِيرٌۭ مِّنْهُمْ فَٰسِقُونَ", transliteration: "Walaqad arsalna noohan waibraheema wajaAAalna fee thurriyyatihima alnnubuwwata waalkitaba faminhum muhtadin wakatheerun minhum fasiqoona", transliterationB: "Wa laqad arsalnaa Noohanw wa Ibraaheema wa ja'alnaa fee zurriyyatihiman nubuwwata wal Kitaaba faminhum muhtad; wa kaseerum minhum faasiqoon", english: "And We sent Noah and Abraham, and established in their line Prophethood and Revelation: and some of them were on right guidance. But many of them became rebellious transgressors", romanUrdu: "Humne Nooh aur Ibrahim ko bheja aur un dono ki nasal mein nabuwat aur kitaab rakh di phir unki aulad mein se kisi ne hidayat ikhtiyar ki aur bahut se faasiq ho gaye" },
    { number: 27, arabic: "ثُمَّ قَفَّيْنَا عَلَىٰٓ ءَاثَٰرِهِم بِرُسُلِنَا وَقَفَّيْنَا بِعِيسَى ٱبْنِ مَرْيَمَ وَءَاتَيْنَٰهُ ٱلْإِنجِيلَ وَجَعَلْنَا فِى قُلُوبِ ٱلَّذِينَ ٱتَّبَعُوهُ رَأْفَةًۭ وَرَحْمَةًۭ وَرَهْبَانِيَّةً ٱبْتَدَعُوهَا مَا كَتَبْنَٰهَا عَلَيْهِمْ إِلَّا ٱبْتِغَآءَ رِضْوَٰنِ ٱللَّهِ فَمَا رَعَوْهَا حَقَّ رِعَايَتِهَا ۖ فَـَٔاتَيْنَا ٱلَّذِينَ ءَامَنُوا۟ مِنْهُمْ أَجْرَهُمْ ۖ وَكَثِيرٌۭ مِّنْهُمْ فَٰسِقُونَ", transliteration: "Thumma qaffayna AAala atharihim birusulina waqaffayna biAAeesa ibni maryama waataynahu alinjeela wajaAAalna fee quloobi allatheena ittabaAAoohu rafatan warahmatan warahbaniyyatan ibtadaAAooha ma katabnaha AAalayhim illa ibtighaa ridwani Allahi fama raAAawha haqqa riAAayatiha faatayna allatheena amanoo minhum ajrahum wakatheerun minhum fasiqoona", transliterationB: "Summa qaffainaa 'alaa aasaarihim bi Rusulinaa wa qaffainaa be 'Eesab ni Maryama wa aatainaahul Injeela wa ja'alnaa fee quloobil lazeenat taba' oohu raafatanw wa rahmatanw wa rahbaaniyyatanib tada' oohaa maa katanaahaa 'alaihim illab tighaaa'a ridwaanil laahi famaa ra'awhaa haqqa ri'aayatihaa fa aatainal lazeena aamanoo minhum ajrahum wa kaseerum minhum faasiqoon", english: "Then, in their wake, We followed them up with (others of) Our messengers: We sent after them Jesus the son of Mary, and bestowed on him the Gospel; and We ordained in the hearts of those who followed him Compassion and Mercy. But the Monasticism which they invented for themselves, We did not prescribe for them: (We commanded) only the seeking for the Good Pleasure of Allah; but that they did not foster as they should have done. Yet We bestowed, on those among them who believed, their (due) reward, but many of them are rebellious transgressors", romanUrdu: "Unke baad humne pai dar pai (succession) apne Rasool bheje, aur in sabke baad Isa ibn-e-Maryam ko maboos kiya aur usko Injil ata ki, aur jin logon ne uski pairvi ikhtiyar ki unke dilon mein humne taras (tenderness ) aur reham daal diya. Aur rahbaniyat (monasticism) unhon ne khud ijaad karli, humne usey unpar farz nahin kiya tha. Magar Allah ki khushnudi ki talab mein unhon ne aap hi yeh bidaat nikali aur phir iski pabandi karne ka jo haqq tha usey ada na kiya. Unmein se jo log iman laye huye thay unka ajr humne unko ata kiya, magar unmein se aksar log faasiq hain" },
    { number: 28, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَءَامِنُوا۟ بِرَسُولِهِۦ يُؤْتِكُمْ كِفْلَيْنِ مِن رَّحْمَتِهِۦ وَيَجْعَل لَّكُمْ نُورًۭا تَمْشُونَ بِهِۦ وَيَغْفِرْ لَكُمْ ۚ وَٱللَّهُ غَفُورٌۭ رَّحِيمٌۭ", transliteration: "Ya ayyuha allatheena amanoo ittaqoo Allaha waaminoo birasoolihi yutikum kiflayni min rahmatihi wayajAAal lakum nooran tamshoona bihi wayaghfir lakum waAllahu ghafoorun raheemun", transliterationB: "Yaaa ayyuhal lazeena aamaanut taqullaaha wa aaminoo bi Rasoolihee yu'tikum kiflaini mir rahmatihee wa yaj'al lakum nooran tamshoona bihee wa yaghfir lakum; wallaahu Ghafoorur Raheem", english: "O ye that believe! Fear Allah, and believe in His Messenger, and He will bestow on you a double portion of His Mercy: He will provide for you a Light by which ye shall walk (straight in your path), and He will forgive you (your past): for Allah is Oft-Forgiving, Most Merciful", romanUrdu: "Aey logon jo iman laye ho, Allah se daro aur uske Rasool par iman lao. Allah tumhein apni Rehmat ka dohra hissa ata farmyega aur tumhein wahi noor bakhshega jiski roshni mein tum chaloge, aur tumhare kasoor maaf kardega.Allah bada maaf karne wala aur meharbaan hai" },
    { number: 29, arabic: "لِّئَلَّا يَعْلَمَ أَهْلُ ٱلْكِتَٰبِ أَلَّا يَقْدِرُونَ عَلَىٰ شَىْءٍۢ مِّن فَضْلِ ٱللَّهِ ۙ وَأَنَّ ٱلْفَضْلَ بِيَدِ ٱللَّهِ يُؤْتِيهِ مَن يَشَآءُ ۚ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ", transliteration: "Lialla yaAAlama ahlu alkitabi alla yaqdiroona AAala shayin min fadli Allahi waanna alfadla biyadi Allahi yuteehi man yashao waAllahu thoo alfadli alAAatheemi", transliterationB: "Li'alla ya'lama Ahlul kitaabi allaa yaqdiroona 'alaa shai'im min fadlil laahi wa annal fadla bi Yadil laahi u'teehi many yashaaa'; wallaahu Zul fadilil 'azeem", english: "That the People of the Book may know that they have no power whatever over the Grace of Allah, that (His) Grace is (entirely) in His Hand, to bestow it on whomsoever He wills. For Allah is the Lord of Grace abounding", romanUrdu: "(Tumko yeh rawish ikhtiyar karni chahiye) taa-ke ehle kitaab ko maalom ho jaye ke Allah ke fazal par unka koi ijara (control/ikhtiyar) nahin hai, aur yeh ke Allah ka fazal uske apne hi haath mein hai, Jisey chahta hai ata farmata hai. Aur woh badey fazal(bounty) wala hai" }
  ]
};
